SELECT COUNT(*) FROM hm_query.pricing_rule_flat

    AND rule_type = #{ruleType}
    AND active = #{active}
    AND name LIKE CONCAT('%', #{name}, '%')
    AND has_conflict = #{hasConflict}

SELECT rule_id as "id", name as "ruleName", rule_type as "ruleType", priority as "priority", discount_type as "discountType", discount_value as "discountValue", active as "active", active_from as "activeFrom", active_to as "activeTo", products_affected as "productsAffected", conversions_30d as "conversions30d", conversion_rate as "conversionRate", revenue_impact as "revenueImpact", has_conflict as "hasConflict", conflict_details as "conflictDetails", created_time as "createdAt", created_by as "createdBy" FROM hm_query.pricing_rule_flat
AND rule_type = #{ruleType} AND active = #{active} AND name LIKE CONCAT('%', #{name}, '%') AND has_conflict = #{hasConflict}
${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.price_change_log_flat

    AND product_id = #{productId}
    AND product_name LIKE CONCAT('%', #{productName}, '%')
    AND changed_by = #{changedBy}
    AND (product_name LIKE CONCAT('%', #{q}, '%') OR sku LIKE CONCAT('%', #{q}, '%'))

SELECT id, product_id as "productId", product_name as "productName", sku as "sku", old_price as "oldPrice", new_price as "newPrice", change_pct as "changePct", change_reason as "changeReason", changed_by as "changedBy", change_time as "createdAt" FROM hm_query.price_change_log_flat
AND product_id = #{productId} AND product_name LIKE CONCAT('%', #{productName}, '%') AND changed_by = #{changedBy} AND (product_name LIKE CONCAT('%', #{q}, '%') OR sku LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
